import java.util.concurrent.Callable;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;

import org.apache.commons.math3.linear.Array2DRowRealMatrix;
import org.apache.commons.math3.linear.RealMatrix;

public class MatrixMultiplication {
    private static final int ROWS = 1000;
    private static final int COLS = 1000;
    private static final int NUM_THREADS = Runtime.getRuntime().availableProcessors();

    public static void main(String[] args) throws Exception {
        // Create two random matrices
        RealMatrix A = new Array2DRowRealMatrix(ROWS, COLS);
        RealMatrix B = new Array2DRowRealMatrix(COLS, COLS);

        for (int i = 0; i < ROWS; i++) {
            for (int j = 0; j < COLS; j++) {
                A.setEntry(i, j, Math.random());
            }
        }

        for (int j = 0; j < COLS; j++) {
            for (int k = 0; k < COLS; k++) {
                B.setEntry(j, k, Math.random());
            }
        }

        // Create a future array to store the results of each thread
        Future<RealMatrix>[] futures = new Future[NUM_THREADS];

        // Create an executor service to manage the threads
        ExecutorService executor = Executors.newFixedThreadPool(NUM_THREADS);

        // Divide the matrix multiplication into smaller sub-problems and assign them to threads
        for (int i = 0; i < NUM_THREADS; i++) {
            int startRow = i * ROWS / NUM_THREADS;
            int endRow = (i + 1) * ROWS / NUM_THREADS;
            int startCol = 0;
            int endCol = COLS - 1;

            Callable<RealMatrix> task = new MatrixTask(A, B, startRow, endRow, startCol, endCol);
            futures[i] = executor.submit(task);
        }

        // Wait for all threads to complete
        for (Future<RealMatrix> future : futures) {
            future.get();
        }

        // Shut down the executor service
        executor.shutdown();

        // Calculate the final result by summing up the results from each thread
        RealMatrix result = new Array2DRowRealMatrix(ROWS, COLS);
        for (int i = 0; i < NUM_THREADS; i++) {
            RealMatrix temp = futures[i].get();
            for (int j = i * ROWS / NUM_THREADS; j < (i + 1) * ROWS / NUM_THREADS; j++) {
                for (int k = 0; k < COLS; k++) {
                    result.setEntry(j, k, result.getEntry(j, k) + temp.getEntry(j, k));
                }
            }
        }

        // Print the resulting matrix
        System.out.println("Resulting Matrix:");
        System.out.println(result);
    }

    private static class MatrixTask implements Callable<RealMatrix> {
        private final RealMatrix A;
        private final RealMatrix B;
        private final int startRow;
        private final int endRow;
        private final int startCol;
        private final int endCol;

        public MatrixTask(RealMatrix A, RealMatrix B, int startRow, int endRow, int startCol, int endCol) {
            this.A = A;
            this.B = B;
            this.startRow = startRow;
            this.endRow = endRow;
            this.startCol = startCol;
            this.endCol = endCol;
        }

        @Override
        public RealMatrix call() throws Exception {
            RealMatrix C = new Array2DRowRealMatrix(endRow - startRow + 1, endCol - startCol + 1);
            for (int i = startRow; i <= endRow; i++) {
                for (int j = startCol; j <= endCol; j++) {
                    double sum = 0;
                    for (int k = startCol; k <= endCol; k++) {
                        sum += A.getEntry(i, k) * B.getEntry(k, j);
                    }
                    C.setEntry(i - startRow, j - startCol, sum);
                }
            }
            return C;
        }
    }
}
