use std::fs;
use std::io;
use std::collections::HashMap;
use std::str::FromStr;
use std::path::Path;
use std::fmt;

// Define a custom error type for file operations
#[derive(Debug)]
pub enum Error {
    Io(io::Error),
    ParseError,
}

impl From<io::Error> for Error {
    fn from(e: io::Error) -> Self {
        Error::Io(e)
    }
}

impl From<fs::File> for Error {
    fn from(_: fs::File) -> Self {
        Error::ParseError
    }
}

impl fmt::Display for Error {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            Error::Io(e) => write!(f, "I/O error: {}", e),
            Error::ParseError => write!(f, "Error parsing file"),
        }
    }
}

fn main() {
    let filename = "words.txt";
    let word_count: HashMap<String, u32> = process_file(filename)
        .expect("Failed to process file");

    for (word, count) in word_count.into_iter().take(5) {
        println!("{}: {}", word, count);
    }
}

fn process_file(filename: &str) -> Result<HashMap<String, u32>, Error> {
    let file_path = Path::new(filename);
    if !file_path.exists() {
        return Err(Error::ParseError);
    }

    let mut file = match fs::File::open(file_path) {
        Ok(file) => file,
        Err(e) => return Err(Error::Io(e)),
    };

    let mut word_count: HashMap<String, u32> = HashMap::new();

    let mut buffer = String::new();
    match file.read_to_string(&mut buffer) {
        Ok(_) => (),
        Err(e) => return Err(Error::Io(e)),
    }

    let words: Vec<_> = buffer.split_whitespace()
        .map(|s| s.to_lowercase().replace("[^a-z0-9]", ""))
        .collect();

    for word in words {
        *word_count.entry(word).or_insert(0) += 1;
    }

    Ok(word_count)
}
