#include <iostream>
#include <fstream>
#include <vector>
#include <algorithm>

// Custom comparator for sorting integers in descending order
struct DescendingComparator {
    bool operator()(int a, int b) const {
        return a < b;
    }
};

int main() {
    // Input file name
    std::string inputFile = "input.txt";

    // Output file name
    std::string outputFile = "output.txt";

    try {
        // Read integers from input file
        std::ifstream file(inputFile);
        if (!file.is_open()) {
            throw std::runtime_error("Failed to open input file.");
        }

        std::vector<int> numbers;
        int num;
        while (file >> num) {
            numbers.push_back(num);
        }
        file.close();

        // Sort integers in descending order
        std::sort(numbers.begin(), numbers.end(), DescendingComparator());

        // Write sorted integers to output file
        file.open(outputFile);
        if (!file.is_open()) {
            throw std::runtime_error("Failed to open output file.");
        }

        for (int num : numbers) {
            file << num << std::endl;
        }
        file.close();
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return 1;
    }

    return 0;
}
