const crypto = require('crypto');
const lru_cache = require('lru-cache');
const { Buffer } = require('buffer');

class Memoized {
  constructor(ttl = 60, max = 100) {
    this.cache = lru_cache({
      max: max,
      maxAge: ttl,
      hash: (key) => this._hash(key),
      serialize: (key, value) => {
        return {
          key,
          value,
        };
      },
      deserialize: (data) => {
        return {
          key: data.key,
          value: data.value,
        };
      },
      compare: (a, b) => {
        return this._hash(a.key) === this._hash(b.key);
      },
    });

    this.flush = () => {
      this.cache.clear();
    };
  }

  _hash(key) {
    const signature = crypto.createHash('sha256');
    signature.update(key);
    return signature.digest().toString('hex');
  }

  decorator(fn) {
    return (...args) => {
      const key = this._hash(JSON.stringify(args));
      const cachedResult = this.cache.get(key);
      if (cachedResult) {
        return cachedResult.value;
      }

      const result = fn(...args);
      this.cache.set(key, { key, value: result });
      return result;
    };
  }
}

module.exports = Memoized;
