import java.io.File;
import java.io.FileNotFoundException;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Scanner;

public class ProductFilter {
    public static void main(String[] args) {
        List<Product> products = readProductsFromFile("products.txt");
        products.removeIf(product -> product.getPrice() < 20);
        Collections.sort(products, (p1, p2) -> Double.compare(p2.getPrice(), p1.getPrice()));
        printProducts(products);
    }

    private static List<Product> readProductsFromFile(String filename) {
        List<Product> products = new ArrayList<>();
        try (Scanner scanner = new Scanner(new File(filename))) {
            while (scanner.hasNextLine()) {
                String[] parts = scanner.nextLine().split(",");
                products.add(new Product(parts[0].trim(), Double.parseDouble(parts[1].trim())));
            }
        } catch (FileNotFoundException e) {
            System.err.println("File not found: " + filename);
        }
        return products;
    }

    private static void printProducts(List<Product> products) {
        for (Product product : products) {
            System.out.println(product.getName() + ": $" + product.getPrice());
        }
    }

    private static class Product {
        private String name;
        private double price;

        public Product(String name, double price) {
            this.name = name;
            this.price = price;
        }

        public String getName() {
            return name;
        }

        public double getPrice() {
            return price;
        }
    }
}
