#include <cstdint>
#include <numeric>
#include <iostream>

template <size_t N>
constexpr uint32_t crc32(const uint8_t (&data)[N]) {
    uint32_t crc = 0xFFFFFFFF;
    std::transform(data, data + N, data, [crc](uint8_t x) {
        crc = (crc >> 8) ^ ((crc & 0xFF) ^ x);
    });
    return ~crc;
}

int main() {
    const uint8_t data1[] = {0x01, 0x02, 0x03, 0x04};
    const uint8_t data2[] = {0x05, 0x06, 0x07, 0x08};

    std::cout << "CRC32 of data1: " << crc32(data1) << std::endl;
    std::cout << "CRC32 of data2: " << crc32(data2) << std::endl;

    return 0;
}
