import java.util.concurrent.atomic.AtomicLong;
import java.util.stream.Stream;
import java.util.Random;

public class SensorReadingsAnalysis {

    public static void main(String[] args) {
        int numReadings = 1000000;
        int threshold = 10;

        var sensorReadings = generateSensorReadings(numReadings);
        var analysisResult = analyzeSensorReadings(sensorReadings, threshold);

        System.out.println("Anomalies detected: " + analysisResult.getAnomaliesCount());
        System.out.println("Mean reading: " + analysisResult.getMeanReading());
        System.out.println("Median reading: " + analysisResult.getMedianReading());
    }

    private static Stream<Integer> generateSensorReadings(int numReadings) {
        var random = new Random();
        return Stream.generate(() -> random.nextInt(100))
                .limit(numReadings);
    }

    private static SensorReadingsAnalysisResult analyzeSensorReadings(Stream<Integer> sensorReadings, int threshold) {
        var atomicAnomaliesCount = new AtomicLong(0);
        var sum = 0L;
        var sumSquares = 0L;

        sensorReadings.parallelStream()
                .forEach(readings -> {
                    long reading = readings.get();
                    sum += reading;
                    sumSquares += reading * reading;

                    if (reading > threshold) {
                        atomicAnomaliesCount.incrementAndGet();
                    }
                });

        var meanReading = sum / sensorReadings.count();
        var medianReading = getMedian(sum, sensorReadings.count());

        return new SensorReadingsAnalysisResult(
                atomicAnomaliesCount.get(),
                meanReading,
                medianReading
        );
    }

    private static double getMedian(long sum, int count) {
        var sortedReadings = Stream.of(sensorReadings().toArray())
                .sorted()
                .limit(count / 2)
                .toArray();

        return count % 2 == 0 ? (sortedReadings[sortedReadings.length / 2 - 1] + sortedReadings[sortedReadings.length / 2]) / 2.0 : sortedReadings[count / 2];
    }

    private static Stream<Integer> sensorReadings() {
        var random = new Random();
        return Stream.generate(() -> random.nextInt(100))
                .limit(100);
    }

    private static class SensorReadingsAnalysisResult {
        private final long anomaliesCount;
        private final double meanReading;
        private final double medianReading;

        public SensorReadingsAnalysisResult(long anomaliesCount, double meanReading, double medianReading) {
            this.anomaliesCount = anomaliesCount;
            this.meanReading = meanReading;
            this.medianReading = medianReading;
        }

        public long getAnomaliesCount() {
            return anomaliesCount;
        }

        public double getMeanReading() {
            return meanReading;
        }

        public double getMedianReading() {
            return medianReading;
        }
    }
}
