class GraphQLResponse {
  constructor(data) {
    this.data = data;
  }

  toReactiveObject() {
    const reactiveObject = {};

    Object.keys(this.data).forEach((key) => {
      const value = this.data[key];

      if (Array.isArray(value)) {
        reactiveObject[key] = value.map((item) => new GraphQLResponse(item).toReactiveObject());
      } else if (typeof value === 'object') {
        reactiveObject[key] = new GraphQLResponse(value).toReactiveObject();
      } else {
        reactiveObject[key] = value;
      }
    });

    return reactiveObject;
  }
}

class ReactiveObject {
  constructor(data) {
    this.data = data;
  }

  get computedProperty() {
    // cached computed property
    if (!this.computedProperty) {
      this.computedProperty = this.data;
    }

    return this.computedProperty;
  }
}

const graphqlResponse = new GraphQLResponse({
  data: {
    users: [
      { id: 1, name: 'John Doe', posts: [{ id: 1, content: 'Hello World' }] },
      { id: 2, name: 'Jane Doe', posts: [{ id: 2, content: 'Foo Bar' }] },
    ],
  },
});

const reactiveObject = graphqlResponse.toReactiveObject();

console.log(reactiveObject.users[0].computedProperty); // { id: 1, name: 'John Doe', posts: [ { id: 1, content: 'Hello World' } ] }
console.log(reactiveObject.users[1].computedProperty); // { id: 2, name: 'Jane Doe', posts: [ { id: 2, content: 'Foo Bar' } ] }
