use tokio;
use tokio::sync::mpsc;
use futures::stream::Map;
use futures::future::{ok, Err};
use futures::StreamExt;

async fn process_telemetry(device_id: String, telemetry: String) -> String {
    println!("Processing telemetry for device {}: {}", device_id, telemetry);
    tokio::time::sleep(tokio::time::Duration::from_secs(1)).await;
    println!("Finished processing telemetry for device {}", device_id);
    device_id
}

#[tokio::main]
async fn main() {
    let (tx, rx) = mpsc::channel(100);
    let stream = rx.map(|(device_id, telemetry)| process_telemetry(device_id, telemetry))
        .map_err(|e| e.to_string())
        .map(|result| {
            let (device_id, result) = result.split_once(':').unwrap();
            (device_id.to_string(), result.to_string())
        });

    for (device_id, telemetry) in tokio::stream::iter::once((("device1", "telemetry1"), ("device2", "telemetry2"))) {
        tx.send((device_id, telemetry)).await.unwrap();
    }

    tokio::select! {
        _ = stream.next() => {
            println!("Channel is closed");
        },
        msg = stream.next() => {
            match msg {
                None => {
                    println!("Channel is closed");
                },
                Some(msg) => {
                    println!("Received message: {}", msg);
                }
            }
        }
    }
}
