import React, { useState, useEffect } from 'react';
import { View, Animated, PanResponder, StyleSheet } from 'react-native';
import { SVG } from 'react-native-svg';

const MorphingPaths = () => {
  const [pathData, setPathData] = useState([
    'M 50 0 C 25 0 0 25 0 50',
    'M 50 50 C 25 50 0 75 0 100',
    'M 50 100 C 25 100 0 125 0 150',
    'M 50 150 C 25 150 0 175 0 200',
  ]);

  const [rotation, setRotation] = useState(new Animated.Value(0));
  const [scale, setScale] = useState(new Animated.Value(1));

  const panResponder = PanResponder.create({
    onStartShouldSetPanResponder: () => true,
    onPanResponderMove: (evt, gestureState) => {
      const { dy } = gestureState;
      Animated.spring(rotation, {
        toValue: dy * 10,
        useNativeDriver: true,
      }).start();
      Animated.spring(scale, {
        toValue: Math.abs(dy) * 0.1,
        useNativeDriver: true,
      }).start();
    },
  });

  useEffect(() => {
    const rotate = () => {
      const rotatedPathData = pathData.map((path) => {
        const [x, y, ...coords] = path.split(' ');
        return `M ${x} ${y} C ${x} ${y + Math.abs(x)} ${x + Math.abs(y)} ${y} ${x} ${y}`;
      });
      setPathData(rotatedPathData);
    };
    const scalePathData = () => {
      const scaledPathData = pathData.map((path) => {
        const [x, y, ...coords] = path.split(' ');
        return `M ${x * scale} ${y * scale} C ${x * scale} ${y * scale + Math.abs(x * scale)} ${x * scale + Math.abs(y * scale)} ${y * scale} ${x * scale} ${y * scale}`;
      });
      setPathData(scaledPathData);
    };
    const rotateAndScale = () => {
      rotate();
      scalePathData();
    };
    const handleRotationChange = Animated.event([
      { nativeEvent: { value: rotation } },
    ]);
    const handleScaleChange = Animated.event([
      { nativeEvent: { value: scale } },
    ]);
    Animated.event([handleRotationChange, handleScaleChange]).start();
    const rotationAnim = Animated.timing(rotation, {
      toValue: 360,
      useNativeDriver: true,
    });
    const scaleAnim = Animated.timing(scale, {
      toValue: 1.2,
      useNativeDriver: true,
    });
    rotationAnim.start();
    scaleAnim.start();
    return () => {
      rotationAnim.cancel();
      scaleAnim.cancel();
    };
  }, [pathData]);

  return (
    <View style={[styles.container, { transform: [{ rotateX: rotation }, { rotateY: rotation }] }]}>
      {pathData.map((path, index) => (
        <SVG
          key={index}
          width={300}
          height={200}
          viewBox="0 0 300 200"
          fill="none"
          stroke="#000"
          strokeWidth="2"
        >
          <path d={path} />
        </SVG>
      ))}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
});

export default MorphingPaths;
